+(VPTransformState &State) {
+  IRBuilder<> &Builder = State.Builder;
+  auto *IG = cast<InterleaveGroup<Instruction>>(getInterleaveGroup());
+  unsigned Index = IG->getInsertPos();
+
+  Value *NewVec = State.VPValue2Value[getOperand(0)];
+  Value *ExtractedMember = Builder.CreateExtractElement(NewVec, Index);
+  State.VPValue2Value[getVPValue()] = ExtractedMember;
+}
