+void VPPartialReductionRecipe::execute(VPTransformState &State) {
+  IRBuilder<> &Builder = State.Builder;
+  auto *RedInst = cast<Instruction>(getUnderlyingValue());
+  Value *NextV = State.VPValue2Value[getOperand(0)];
+  Value *NewRedInst = Builder.CreateBinOp(
+      (Instruction::BinaryOps)RedInst->getOpcode(), NextV,
+      State.VPValue2Value[getOperand(1)], RedInst->getName());
+  State.VPValue2Value[getVPValue()] = NewRedInst;
+}
