+  IRBuilder<> &Builder = State.Builder;
+  Value *Mem = State.VPValue2Value[getOperand(0)];
+  Value *Val = State.VPValue2Value[getOperand(1)];
+  Builder.CreateStore(Val, Mem);
+}
+
+void VPStoreRecipe::print(raw_ostream &O, const Twine &Indent) const {
+  O << Indent << "STORE ";
+  printOperands(O);
+  O << "\n";
+}
